// Les variables sont stockées dans deux types de stockage : "default" et "file".
// Ce nœud synchronise les variables globales avec enrichedVars.
// Il met à jour enrichedVars avec les variables globales actuelles
// et s'assure que chaque variable suit la nouvelle structure définie.

// Les variables sont structurées avec des propriétés comme nomVarG, instances, propriétés, etc.
// La fonction gère également la restauration des variables globales manquantes depuis enrichedVars.
// Elle prend en compte les instances et les sous-variables pour une synchronisation cohérente.

func:
// --- ROUTER ACTION (Version Propre) ---
let action = msg.payload.action; // editBase, editValues, delete
let prop = msg.payload.row;     // Données de la ligne cliquée

// On stocke le nom original pour gérer les renommages dans SauvResultat
flow.set("propOriginalName", (prop.nomP === 'NouvelleP') ? null : prop.nomP);

// CAS : AJOUT (Ligne NouvelleP)
if (prop._isNew) {
    msg.topic = "openEditor";
    msg.editor = "base";
    msg.originalName = null;
    msg.prop = {
        nomP: "",
        descriptionP: "",
        typeP: "string",
        optionsP: []
    };
    return [msg, null, null]; // Vers Template Base
}

// CAS : MODIFICATION STRUCTURE
if (action === "editBase") {
    msg.topic = "openEditor";
    msg.editor = "base";
    msg.originalName = prop.nomP;
    msg.prop = {
        nomP: prop.nomP,
        descriptionP: prop.descriptionP,
        typeP: prop.typeP,
        optionsP: prop.optionsP || []
    };
    return [msg, null, null]; // Vers Template Base
}

// CAS : MODIFICATION VALEURS (Par instance)
if (action === "editValues") {
    msg.payload = prop.valeurs || {};
    msg.propName = prop.nomP;
    return [null, msg, null]; // Vers Formulaire Valeurs
}

// CAS : SUPPRESSION
if (action === "delete") {
    msg.topic = "delete";
    msg.prop = prop;
    return [null, null, msg]; // Vers SauvResultat
}

return null;

// --- PREPA TABLEAU PROPRIETES (Version Propre) ---
let varSelected = flow.get('varSelected') || null;
let enrichedVars = global.get('enrichedVars') || {};
let variable = enrichedVars[varSelected] || {};

// Si aucune variable n'est sélectionnée
if (!varSelected || varSelected === "new") {
    msg.payload = {
        proprietes: [],
        variable: { nomVarG: "Sélectionnez une variable" }
    };
    return msg;
}

// Mapping des propriétés avec les nouveaux noms de champs
let proprietes = (variable.proprietes || []).map(p => ({
    nomP: p.nomP,
    descriptionP: p.descriptionP || "",
    typeP: p.typeP || "string",
    valeurs: p.valeurs || {},
    optionsP: p.optionsP || [], // Nouvelle nomenclature
    _locked: p._locked || false
}));

// Ligne virtuelle pour l'ajout d'une nouvelle propriété
if (varSelected && varSelected !== "new") {
    proprietes.push({
        nomP: 'NouvelleP',
        descriptionP: 'Cliquer pour ajouter une nouvelle propriété',
        typeP: 'string',
        optionsP: [],
        _isNew: true
    });
}

msg.payload = {
    proprietes: proprietes,
    instances: (variable.instances || []).filter(i => i !== '*'),
    variable: { nomVarG: variable.nomVarG || varSelected }
};

return msg;

// --- SAUV RESULTAT ACTIONS (Version Propre) ---
const nodeFs = global.get('nodeFs');
const filePath = '/data/data/com.termux/files/home/.node-red/globalSave.json';

let enriched = global.get('enrichedVars') || {};
let varSelected = flow.get('varSelected');
let originalName = flow.get("propOriginalName");

if (!varSelected || !enriched[varSelected]) return null;
let variable = enriched[varSelected];
variable.proprietes = variable.proprietes || [];

// 1. GESTION DES ACTIONS
if (msg.topic === "saveBase") {
    // Reçu depuis ton nouveau template Vue.js
    let p = msg.payload; 
    let idx = variable.proprietes.findIndex(pr => pr.nomP === originalName);

    let updatedProp = {
        nomP: p.nomP,
        descriptionP: p.descriptionP,
        typeP: p.typeP,
        optionsP: p.optionsP || [],
        valeurs: (idx >= 0) ? variable.proprietes[idx].valeurs : {}
    };

    if (idx === -1) {
        // Initialisation des instances pour une nouvelle propriété
        (variable.instances || ["*"]).forEach(inst => {
            updatedProp.valeurs[inst] = (p.typeP === "number") ? 0 : "";
        });
        variable.proprietes.push(updatedProp);
    } else {
        variable.proprietes[idx] = updatedProp;
    }
} 
else if (msg.topic === "saveValues") {
    // Reçu depuis le formulaire des valeurs par instance
    let idx = variable.proprietes.findIndex(pr => pr.nomP === originalName);
    if (idx >= 0) {
        variable.proprietes[idx].valeurs = msg.payload;
    }
}
else if (msg.topic === "delete") {
    variable.proprietes = variable.proprietes.filter(pr => pr.nomP !== originalName);
}

// 2. ENREGISTREMENT ET MISE À JOUR MÉMOIRE
global.set('enrichedVars', enriched);

try {
    const out = { enrichedVars: enriched, lastUpdate: new Date().toISOString() };
    nodeFs.writeFileSync(filePath, JSON.stringify(out, null, 4), 'utf8');
    node.status({fill:"green", shape:"dot", text:"💾 Fichier synchronisé"});
} catch (err) {
    node.error("Erreur écriture fichier : " + err.message);
    node.status({fill:"red", shape:"ring", text:"Erreur disque"});
}

// 3. RAFRAICHISSEMENT UI
flow.set("propOriginalName", null);
msg.topic = "refresh";
return msg;

// Noeud "Gestion Sélection Automatique" - VERSION CORRIGÉE
let varSelected = msg.payload;

console.log("Gestion Sélection Automatique - varSelected:", varSelected);

if (varSelected && varSelected !== "new") {
    // Variable existante sélectionnée
    flow.set('varSelected', varSelected);
    console.log("Variable sélectionnée automatiquement:", varSelected);

    // Préparer les messages pour les deux composants
    let formMsg = {
        topic: "refresh",
        payload: varSelected,
        info: `✅ Vous êtes sur la variable : ${varSelected}`
    };

    let tableauMsg = {
        topic: 'refresh',
        view: 'tableau',
        payload: varSelected
    };

    return [formMsg, tableauMsg];

} else if (varSelected === "new") {
    // Nouvelle variable
    flow.set('varSelected', "new");

    // Préparer les messages pour les deux composants
    let formMsg = {
        topic: "newVarG",
        info: "➕ Création d'une nouvelle variable.",
        payload: {
            nomVarG: "",
            nomCpletVarG: "",
            instances: "*",
            descriptionVarG: "- Objectif(s): - Origine: - Autres : ",
            dateUpdateVarG: new Date().toISOString()
        }
    };

    let tableauMsg = {
        topic: 'refresh',
        view: 'tableau',
        payload: "new"
    };

    return [formMsg, tableauMsg];

} else {
    // Aucune sélection
    return [null, null];
}

// Noeud "Initialisation Page"
// S'exécute au chargement de la page pour reset l'état

// Reset les sélections au chargement
flow.set('varSelected', null);
flow.set('propSelected', null);
flow.set('infoAction', "Sélectionnez une variable");

// Préparer un tableau vide
msg.payload = {
    proprietes: [{
        nomP: 'NouvelleP',
        nomCpletP: 'New',
        typeP: null,
        schema: null,
        valeurs: { '*': null },
        _isNew: true
    }],
    propSelected: null,
    instances: [],
    variable: { nomVarG: "Aucune variable sélectionnée" }
};
msg.info = "Sélectionnez une variable dans le tableau";

return msg;

// Voir ce qui existe dans le stockage fichier
let fileData = global.get("enrichedVars", "file");
node.warn("Données dans le fichier: " + JSON.stringify(fileData));

// Voir tous les keys disponibles (si supporté)
try {
    let keys = global.keys("file");
    node.warn("Clés disponibles dans le fichier: " + JSON.stringify(keys));
} catch(e) {
    node.warn("keys() non supporté: " + e.message);
}

/* Le nœud ui-notification envoie un message avec msg.payload contenant :
   - "confirm_clicked" si l'utilisateur clique sur "✅ Supprimer".
   - "dismiss_clicked" si l'utilisateur clique sur "❌ Annuler".
*/
if (msg.payload === "confirm_clicked") {
    const varToDelete = flow.get("pendingDeletion");

    if (!varToDelete) {
        msg.info = "⚠️ Aucune variable en attente de suppression.";
        return msg;
    }

    // Suppression
    let enrichedVars = global.get("enrichedVars", "file") || {};
    delete enrichedVars[varToDelete];
    delete enrichedVars[""];
    global.set("enrichedVars", enrichedVars, "file");
    global.set(varToDelete, undefined, "default");
    flow.set("varSelected", "none");
    flow.set("pendingDeletion", null);

    msg.payload = "none";
    msg.info = `✅ Variable "${varToDelete}" supprimée.`;
    msg.notification = {
        type: "success",
        title: "✅ Supprimée",
        text: `Variable "${varToDelete}" supprimée avec succès.`,
        duration: 3000
    };

} else if (msg.payload === "dismiss_clicked") {
    flow.set("pendingDeletion", null);
    msg.info = "❌ Suppression annulée.";
    msg.notification = {
        type: "info",
        title: "❌ Annulée",
        text: "Suppression annulée.",
        duration: 3000
    };
}

return msg;

// Dans le noeud "routerAction" - version corrigée
let action = msg.action;
let prop = msg.prop || {};
let varSelected = flow.get('varSelected');
let enriched = global.get('enrichedVars', 'file') || {};
let variable = enriched[varSelected] || {};
let instances = (variable.instances || []).filter(i => i !== '*');

if (action) flow.set('propSelected', prop && prop.nomP ? prop.nomP : null);

// CORRECTION : Récupérer la propriété COMPLÈTE depuis la variable
let completeProp = prop;
if (prop.nomP && !prop._isNew) {
    // Chercher la propriété complète dans la variable
    let foundProp = (variable.proprietes || []).find(p => p.nomP === prop.nomP);
    if (foundProp) {
        completeProp = foundProp;
    }
}

// Gestion de l'éditeur Base (nouveau ou modification)
if (action === 'base') {
    // Si c'est une nouvelle propriété (_isNew = true), on envoie un objet vide
    // Sinon, on envoie la propriété complète
    let propData = prop._isNew ? {} : completeProp;

    return [{
        topic: 'openEditor',
        editor: 'base',
        prop: propData,
        instances: instances,
        originalName: prop._isNew ? null : prop.nomP
    }, null, null];
}
// Gestion de l'éditeur Valeurs
else if (action === 'valeurs') {
    return [null, {
        topic: 'openEditor',
        editor: 'valeurs',
        prop: completeProp,  // ← Propriété COMPLÈTE avec useValueList et valueList
        instances: instances,
        originalName: prop.nomP
    }, null];
}
else if (action === 'delete') { 
    return [null, null, { topic: 'delete', prop }]; 
}
return null;
